(ns advent-of-code.day2.1)

(def input  #_ [(vec "ULL")
                (vec "RRDDD")
                (vec "LURDL")
                (vec "UUUUD")]
  [(vec "")
   (vec "")
   (vec "")
   (vec "")
   (vec "")])

#_ input

(def keypad [[1 2 3]
             [4 5 6]
             [7 8 9]])

#_ (get-in keypad [1 1])

#_ (-> keypad (nth 1) (nth 1))

(defn move [[x y] input]
  (let [[nx ny] (case input
                  \U [x (- y 1)]
                  \L [(- x 1) y]
                  \D [x (+ y 1)]
                  \R [(+ x 1) y])]
    (if (and (>= nx 0) (>= ny 0)
             (< nx 3) (< ny 3))
      [nx ny]
      [x y])))

#_ (move [1 1] \U)

(defn key [[[x y] keys] input]
  (let [coords (reduce move
                       [x y]
                       input)]
    [[x y] (conj keys (get-in keypad coords))]))

#_ (key [[1 1] [3 3]] (vec "LURDL"))

(defn solve []
  (second (reduce key
                  [[1 1] []]
                  input)))

#_ (solve)
